const round2 = (value: unknown): number => {
  const numeric = Number(value)
  if (!Number.isFinite(numeric)) return 0
  return Math.round((numeric + Number.EPSILON) * 100) / 100
}

/**
 * Recursively removes undefined values from an object
 * Firebase doesn't accept undefined values in documents
 */
function sanitizeForFirebase(obj: any): any {
  if (obj === null || obj === undefined) {
    return null
  }

  if (Array.isArray(obj)) {
    return obj.map(item => sanitizeForFirebase(item)).filter(item => item !== undefined)
  }

  if (typeof obj === 'object' && obj !== null) {
    const sanitized: any = {}
    for (const [key, value] of Object.entries(obj)) {
      if (value !== undefined) {
        const sanitizedValue = sanitizeForFirebase(value)
        if (sanitizedValue !== undefined) {
          sanitized[key] = sanitizedValue
        }
      }
    }
    return sanitized
  }

  return obj
}

const LOCAL_STORAGE_KEY = 'thisai_crm_invoices'
const getLocalStorageKey = () => getScopedStorageKey(LOCAL_STORAGE_KEY, 'company')

// Duplicate-submit guard for slow UI/network conditions.
// Prevents the same invoice create action from being inserted twice when users click repeatedly.
const INVOICE_CREATE_DEDUP_WINDOW_MS = 8000
const inFlightInvoiceCreateKeys = new Set<string>()
const recentCreatedInvoices = new Map<string, { invoice: Invoice; timestamp: number }>()

const normalizeDedupPart = (value: unknown): string =>
  String(value ?? '').trim().toLowerCase()

const normalizeMoneyForDedup = (value: unknown): string => {
  const n = Number(value)
  if (!Number.isFinite(n)) return '0.00'
  return (Math.round(n * 100) / 100).toFixed(2)
}

const getMillis = (value: unknown): number => {
  const ms = new Date(String(value ?? '')).getTime()
  return Number.isFinite(ms) ? ms : 0
}

const isOfflineInvoiceId = (id: string): boolean =>
  id.startsWith('invoice_') || id.startsWith('offline_')

const getInvoiceIdentityKey = (
  invoiceData: Partial<Invoice>,
  companyIdOverride?: string
): string => {
  const companyId = normalizeDedupPart((invoiceData as any)?.companyId || companyIdOverride || '')
  const type = normalizeDedupPart((invoiceData as any)?.type)
  const invoiceNumber = normalizeDedupPart((invoiceData as any)?.invoiceNumber)

  if (invoiceNumber) {
    return [companyId, type, invoiceNumber].join('|')
  }

  return [
    companyId,
    type,
    normalizeDedupPart((invoiceData as any)?.partyId || (invoiceData as any)?.partyName),
    normalizeDedupPart((invoiceData as any)?.invoiceDate || (invoiceData as any)?.date),
    normalizeMoneyForDedup((invoiceData as any)?.grandTotal ?? (invoiceData as any)?.total ?? 0)
  ].join('|')
}

const choosePreferredInvoice = (
  current: Invoice,
  candidate: Invoice
): Invoice => {
  const currentId = String((current as any)?.id || '')
  const candidateId = String((candidate as any)?.id || '')
  const currentOffline = isOfflineInvoiceId(currentId)
  const candidateOffline = isOfflineInvoiceId(candidateId)

  if (currentOffline !== candidateOffline) {
    return candidateOffline ? current : candidate
  }

  const currentUpdated = getMillis((current as any)?.updatedAt || (current as any)?.createdAt || (current as any)?.invoiceDate)
  const candidateUpdated = getMillis((candidate as any)?.updatedAt || (candidate as any)?.createdAt || (candidate as any)?.invoiceDate)

  if (candidateUpdated > currentUpdated) return candidate
  if (candidateUpdated < currentUpdated) return current

  if ((current as any)?._pendingSync && !(candidate as any)?._pendingSync) return candidate
  if (!(current as any)?._pendingSync && (candidate as any)?._pendingSync) return current

  return current
}

const dedupeInvoicesByIdentity = (
  invoices: Invoice[],
  companyIdOverride?: string
): Invoice[] => {
  const byIdentity = new Map<string, Invoice>()
  for (const invoice of invoices) {
    const key = getInvoiceIdentityKey(invoice as Partial<Invoice>, companyIdOverride)
    const existing = byIdentity.get(key)
    if (!existing) {
      byIdentity.set(key, invoice)
      continue
    }
    byIdentity.set(key, choosePreferredInvoice(existing, invoice))
  }
  return Array.from(byIdentity.values())
}

const buildInvoiceCreateDedupKey = (
  invoiceData: Partial<Invoice>,
  companyId: string
): string => {
  const total = (invoiceData as any)?.grandTotal ?? (invoiceData as any)?.total ?? 0
  const paid = (invoiceData as any)?.payment?.paidAmount ?? (invoiceData as any)?.paidAmount ?? 0

  return [
    companyId,
    normalizeDedupPart((invoiceData as any)?.type),
    normalizeDedupPart((invoiceData as any)?.invoiceNumber),
    normalizeDedupPart((invoiceData as any)?.partyId || (invoiceData as any)?.partyName),
    normalizeDedupPart((invoiceData as any)?.invoiceDate || (invoiceData as any)?.date),
    normalizeMoneyForDedup(total),
    normalizeMoneyForDedup(paid)
  ].join('|')
}

const purgeRecentCreatedInvoiceCache = () => {
  const now = Date.now()
  for (const [key, entry] of recentCreatedInvoices.entries()) {
    if (now - entry.timestamp > INVOICE_CREATE_DEDUP_WINDOW_MS) {
      recentCreatedInvoices.delete(key)
    }
  }
}

const findRecentExistingInvoiceByDedupKey = (
  dedupKey: string,
  companyId: string
): Invoice | null => {
  purgeRecentCreatedInvoiceCache()
  const cached = recentCreatedInvoices.get(dedupKey)
  if (cached) {
    return cached.invoice
  }

  const now = Date.now()
  const localInvoices = getInvoicesFromLocalStorage()
  const matched = localInvoices.find(inv => {
    const invKey = buildInvoiceCreateDedupKey(inv as Partial<Invoice>, companyId)
    if (invKey !== dedupKey) return false

    const createdMs = getMillis((inv as any)?.createdAt || (inv as any)?.updatedAt || (inv as any)?.invoiceDate)
    return createdMs > 0 && (now - createdMs) <= INVOICE_CREATE_DEDUP_WINDOW_MS
  })

  return matched || null
}

const waitForRecentInvoiceByDedupKey = async (
  dedupKey: string,
  companyId: string,
  timeoutMs: number = 3000
): Promise<Invoice | null> => {
  const started = Date.now()
  while (Date.now() - started < timeoutMs) {
    const found = findRecentExistingInvoiceByDedupKey(dedupKey, companyId)
    if (found) return found
    await new Promise(resolve => setTimeout(resolve, 120))
  }
  return null
}

// Helper: filter invoices based on user role
// - Cashier: only sees their own invoices (createdByUserId matches)
// - Manager/Admin: sees all company invoices
const filterByUserRole = (invoices: Invoice[], userInfo: { uid: string; role: string } | null): Invoice[] => {
  if (!userInfo) return invoices

  // Admin and Manager see all invoices
  if (
    userInfo.role === 'admin' ||
    userInfo.role === 'org_admin' ||
    userInfo.role === 'super_admin' ||
    userInfo.role === 'manager'
  ) {
    return invoices
  }

  // Staff/Cashier/Sales visibility is configurable
  if (userInfo.role === 'staff' || userInfo.role === 'cashier' || userInfo.role === 'sales') {
    const visibility = getUserAccessSettings().staffInvoiceVisibility
    if (visibility === 'company') {
      return invoices
    }

    return invoices.filter(inv => {
      const createdBy = (inv as any).createdByUserId
      return createdBy === userInfo.uid
    })
  }

  return invoices
}

// Pagination interface for scalable data fetching
export interface PaginationOptions {
  limit?: number
  offset?: number
  cursor?: string // For cursor-based pagination
  sortBy?: 'invoiceDate' | 'createdAt' | 'invoiceNumber'
  sortOrder?: 'asc' | 'desc'
}

export interface PaginatedResult<T> {
  data: T[]
  total: number
  hasMore: boolean
  nextCursor?: string
  prevCursor?: string
}

// Store last document for cursor-based pagination
let lastDocumentSnapshot: DocumentSnapshot | null = null

/**
 * Get all invoices (with optional type filter) - OFFLINE FIRST + OPTIMIZED
 * Returns from IndexedDB first, then syncs with Firebase in background
 */
export async function getInvoices(type?: 'sale' | 'purchase' | 'quote', limit?: number | null): Promise<Invoice[]> {
  const companyId = getCurrentCompanyId()
  const userInfo = getCurrentUserInfo()

  if (!companyId) {
    console.warn('[getInvoices] Missing companyId - returning empty list')
    return []
  }
  const requestedLimit = typeof limit === 'number' && limit > 0 ? limit : undefined
  const effectiveLimit = requestedLimit ?? 100 // Default limit for better performance

  // Check cache first (2-minute TTL)
  const cacheLimitKey = requestedLimit ?? 'default'
  const cacheKey = type ? `invoices_${type}_${companyId}_${cacheLimitKey}` : `invoices_all_${companyId}_${cacheLimitKey}`
  const cached = getFromCache<Invoice[]>(cacheKey, companyId)
  if (cached) {
    debugLog('[getInvoices] Cache hit:', cached.length, 'invoices')
    return filterByUserRole(cached, userInfo)
  }

  // STEP 1: Always try IndexedDB first (instant, works offline)
  let localInvoices: Invoice[] = []
  try {
    localInvoices = await getAllFromOffline<Invoice>(STORES.INVOICES)
    // Filter by type and companyId locally
    localInvoices = localInvoices.filter(inv => {
      const matchesType = !type || inv.type === type
      const matchesCompany = (inv as any).companyId === companyId
      return matchesType && matchesCompany
    })
    // Sort by invoiceDate descending (single sort)
    localInvoices.sort((a, b) => {
      const dateA = new Date((a as any).invoiceDate || (a as any).createdAt || 0).getTime()
      const dateB = new Date((b as any).invoiceDate || (b as any).createdAt || 0).getTime()
      return dateB - dateA
    })
    localInvoices = dedupeInvoicesByIdentity(localInvoices, companyId)
    debugLog('[getInvoices] Found', localInvoices.length, 'invoices in IndexedDB')
  } catch (error) {
    console.warn('[getInvoices] IndexedDB read failed, trying localStorage:', error)
    localInvoices = getInvoicesFromLocalStorage(type, limit)
  }

  // STEP 2: If offline or Firebase not ready, return local data immediately
  if (!isDeviceOnline() || !isFirebaseReady()) {
    const filtered = filterByUserRole(localInvoices, userInfo)
    const deduped = dedupeInvoicesByIdentity(filtered, companyId)
    const result = requestedLimit ? deduped.slice(0, requestedLimit) : deduped
    debugLog('📱 Offline mode: Returning', result.length, 'invoices')
    return result
  }

  // STEP 3: If online, fetch from Firebase with OPTIMIZED query
  try {
    const invoicesRef = collection(db!, COLLECTIONS.INVOICES)
    let q
    

    // Build optimized query with server-side filtering
    if (companyId && type) {
      // Use composite index: companyId + type + invoiceDate
      q = query(
        invoicesRef,
        where('companyId', '==', companyId),
        where('type', '==', type),
        orderBy('invoiceDate', 'desc'),
        firestoreLimit(effectiveLimit)
      )
    } else if (companyId) {
      // Use index: companyId + invoiceDate
      q = query(
        invoicesRef,
        where('companyId', '==', companyId),
        orderBy('invoiceDate', 'desc'),
        firestoreLimit(effectiveLimit)
      )
    } else {
      // Fallback: no company filter (for legacy/migration)
      q = query(
        invoicesRef,
        orderBy('invoiceDate', 'desc'),
        firestoreLimit(effectiveLimit)
      )
    }

    debugLog('[getInvoices] Fetching with optimized query...')
    const snapshot = await getDocs(q)
    let serverInvoices = snapshot.docs.map(docToInvoice)

    // Store last document for pagination
    if (snapshot.docs.length > 0) {
      lastDocumentSnapshot = snapshot.docs[snapshot.docs.length - 1]
    }

    debugLog('[getInvoices] Optimized query returned:', serverInvoices.length, 'invoices')

    // Role-based filtering (still needed for cashier restriction)
    if (userInfo) {
      serverInvoices = filterByUserRole(serverInvoices, userInfo)
    }
    serverInvoices = dedupeInvoicesByIdentity(serverInvoices, companyId)

    // Merge: Keep local-only items (offline created, not yet synced)
    const serverIds = new Set(serverInvoices.map(inv => String(inv.id || '')))
    const serverIdentityKeys = new Set(
      serverInvoices.map(inv => getInvoiceIdentityKey(inv as Partial<Invoice>, companyId))
    )
    const localOnlyInvoices = localInvoices.filter(inv => {
      const localId = String((inv as any)?.id || '')
      if (!isOfflineInvoiceId(localId)) return false
      if (serverIds.has(localId)) return false
      const identityKey = getInvoiceIdentityKey(inv as Partial<Invoice>, companyId)
      return !serverIdentityKeys.has(identityKey)
    })
    let mergedInvoices = dedupeInvoicesByIdentity([...serverInvoices, ...localOnlyInvoices], companyId)

    // Final sort (single sort after merge)
    mergedInvoices.sort((a, b) => {
      const dateA = new Date((a as any).invoiceDate || (a as any).createdAt || 0).getTime()
      const dateB = new Date((b as any).invoiceDate || (b as any).createdAt || 0).getTime()
      return dateB - dateA
    })

    // Apply final limit
    const result = requestedLimit ? mergedInvoices.slice(0, requestedLimit) : mergedInvoices

    // Update cache
    setInCache(cacheKey, result, companyId)

    // Update local cache with server data (in background, don't await)
    serverInvoices.forEach(invoice => {
      saveToOffline(STORES.INVOICES, invoice).catch(() => {})
    })

    debugLog('☁️ Retrieved:', result.length, 'invoices (server:', serverInvoices.length, ', local-only:', localOnlyInvoices.length, ')')
    return result
  } catch (error: any) {
    // If query fails (e.g., missing index), fall back to simple query
    if (error?.code === 'failed-precondition' || error?.message?.includes('index')) {
      console.warn('[getInvoices] Index missing, falling back to client-side filtering')
      return getInvoicesLegacy(type, limit)
    }
    console.warn('[getInvoices] Firebase fetch failed, returning local data:', error)
    const fallbackInvoices = dedupeInvoicesByIdentity(filterByUserRole(localInvoices, userInfo), companyId)
    return requestedLimit ? fallbackInvoices.slice(0, requestedLimit) : fallbackInvoices
  }
}

/**
 * Legacy fallback for getInvoices when composite index is missing
 * Uses client-side filtering (slower but always works)
 */
async function getInvoicesLegacy(type?: 'sale' | 'purchase' | 'quote', limit?: number | null): Promise<Invoice[]> {
  const companyId = getCurrentCompanyId()
  const userInfo = getCurrentUserInfo()
  const requestedLimit = typeof limit === 'number' && limit > 0 ? limit : undefined

  if (!companyId) {
    console.warn('[getInvoicesLegacy] Missing companyId - returning empty list')
    return []
  }

  try {
    const invoicesRef = collection(db!, COLLECTIONS.INVOICES)
    // Rules-safe fallback: still scope to companyId, then filter client-side.
    const snapshot = await getDocs(query(invoicesRef, where('companyId', '==', companyId)))
    let serverInvoices = snapshot.docs.map(docToInvoice)

    // Client-side filtering
    serverInvoices = serverInvoices.filter(inv => {
      const matchesType = !type || inv.type === type
      return matchesType
    })

    // Role-based filtering
    if (userInfo) {
      serverInvoices = filterByUserRole(serverInvoices, userInfo)
    }
    serverInvoices = dedupeInvoicesByIdentity(serverInvoices, companyId)

    // Sort and limit
    serverInvoices.sort((a, b) => {
      const dateA = new Date((a as any).invoiceDate || (a as any).createdAt || 0).getTime()
      const dateB = new Date((b as any).invoiceDate || (b as any).createdAt || 0).getTime()
      return dateB - dateA
    })

    return requestedLimit ? serverInvoices.slice(0, requestedLimit) : serverInvoices
  } catch (error) {
    console.error('[getInvoicesLegacy] Failed:', error)
    return []
  }
}

/**
 * Get invoices with pagination - SCALABLE VERSION
 * Uses TRUE cursor-based pagination with Firestore startAfter
 */
export async function getInvoicesPaginated(
  type?: 'sale' | 'purchase' | 'quote',
  options: PaginationOptions = {}
): Promise<PaginatedResult<Invoice>> {
  const {
    limit = 20,
    cursor,
    sortBy = 'invoiceDate',
    sortOrder = 'desc'
  } = options

  const companyId = getCurrentCompanyId()
  const userInfo = getCurrentUserInfo()

  // STEP 1: Try IndexedDB first for offline support
  let localInvoices: Invoice[] = []
  try {
    localInvoices = await getAllFromOffline<Invoice>(STORES.INVOICES)

    // Apply filters
    localInvoices = localInvoices.filter(inv => {
      const matchesType = !type || inv.type === type
      const matchesCompany = (inv as any).companyId === companyId
      return matchesType && matchesCompany
    })

    // Apply sorting
    localInvoices.sort((a, b) => {
      const aValue = (a as any)[sortBy] || (a as any).createdAt || 0
      const bValue = (b as any)[sortBy] || (b as any).createdAt || 0

      const comparison = sortOrder === 'desc'
        ? new Date(bValue).getTime() - new Date(aValue).getTime()
        : new Date(aValue).getTime() - new Date(bValue).getTime()

      return comparison
    })
  } catch (error) {
    console.warn('[getInvoicesPaginated] IndexedDB failed:', error)
  }

  // STEP 2: If offline or Firebase not ready, return local data with pagination
  if (!isDeviceOnline() || !isFirebaseReady()) {
    let startIndex = 0
    if (cursor) {
      const cursorIndex = localInvoices.findIndex(inv => inv.id === cursor)
      if (cursorIndex !== -1) {
        startIndex = cursorIndex + 1
      }
    }

    const paginatedData = filterByUserRole(localInvoices.slice(startIndex, startIndex + limit), userInfo)
    const hasMore = startIndex + limit < localInvoices.length

    return {
      data: paginatedData,
      total: localInvoices.length,
      hasMore,
      nextCursor: hasMore && paginatedData.length > 0 ? paginatedData[paginatedData.length - 1].id : undefined
    }
  }

  // STEP 3: Fetch from Firebase with TRUE cursor-based pagination
  try {
    const invoicesRef = collection(db!, COLLECTIONS.INVOICES)
    let q

    // Build base query
    const queryConstraints: any[] = []

    if (companyId) {
      queryConstraints.push(where('companyId', '==', companyId))
    }
    if (type) {
      queryConstraints.push(where('type', '==', type))
    }
    queryConstraints.push(orderBy(sortBy, sortOrder))

    // Add cursor for pagination (startAfter)
    if (cursor && lastDocumentSnapshot) {
      queryConstraints.push(startAfter(lastDocumentSnapshot))
    }

    queryConstraints.push(firestoreLimit(limit + 1)) // Fetch one extra to check hasMore

    q = query(invoicesRef, ...queryConstraints)

    const snapshot = await getDocs(q)
    let serverInvoices = snapshot.docs.map(docToInvoice)

    // Check if there are more results
    const hasMore = serverInvoices.length > limit
    if (hasMore) {
      serverInvoices = serverInvoices.slice(0, limit)
    }

    // Store last document for next page
    if (snapshot.docs.length > 0) {
      lastDocumentSnapshot = snapshot.docs[Math.min(snapshot.docs.length - 1, limit - 1)]
    }

    // Role-based filtering
    if (userInfo) {
      serverInvoices = filterByUserRole(serverInvoices, userInfo)
    }

    const nextCursor = hasMore && serverInvoices.length > 0
      ? serverInvoices[serverInvoices.length - 1].id
      : undefined

    // Update local cache asynchronously
    serverInvoices.forEach(invoice => {
      saveToOffline(STORES.INVOICES, invoice).catch(() => {})
    })

    return {
      data: serverInvoices,
      total: -1, // Firestore doesn't provide total count efficiently
      hasMore,
      nextCursor
    }
  } catch (error: any) {
    console.warn('[getInvoicesPaginated] Firebase fetch failed:', error)

    // Fallback to local data
    let startIndex = 0
    if (cursor) {
      const cursorIndex = localInvoices.findIndex(inv => inv.id === cursor)
      if (cursorIndex !== -1) {
        startIndex = cursorIndex + 1
      }
    }

    const paginatedData = filterByUserRole(localInvoices.slice(startIndex, startIndex + limit), userInfo)

    return {
      data: paginatedData,
      total: localInvoices.length,
      hasMore: startIndex + limit < localInvoices.length
    }
  }
}

/**
 * Get invoice by ID - OFFLINE FIRST
 * Checks IndexedDB first, then localStorage, then Firebase
 */
export async function getInvoiceById(id: string): Promise<Invoice | null> {
  debugLog('[getInvoiceById] Looking for invoice:', id)
  const companyId = getCurrentCompanyId()
  const userInfo = getCurrentUserInfo()
  if (!companyId) {
    return null
  }

  // STEP 1: Try IndexedDB first (instant, works offline)
  try {
    const localInvoice = await getFromOffline<Invoice>(STORES.INVOICES, id)
    if (localInvoice && (localInvoice as any).companyId === companyId) {
      if (filterByUserRole([localInvoice], userInfo).length === 0) {
        return null
      }
      debugLog('[getInvoiceById] Found in IndexedDB:', id)
      return localInvoice
    }
  } catch (error) {
    console.warn('[getInvoiceById] IndexedDB read failed:', error)
  }

  // STEP 2: Check localStorage fallback
  const invoices = getInvoicesFromLocalStorage()
  const localStorageInvoice = invoices.find(i => i.id === id && (i as any).companyId === companyId)
  if (localStorageInvoice) {
    if (filterByUserRole([localStorageInvoice], userInfo).length === 0) {
      return null
    }
    debugLog('[getInvoiceById] Found in localStorage:', id)
    return localStorageInvoice
  }

  // STEP 3: If offline or Firebase not ready, return null
  if (!isDeviceOnline() || !isFirebaseReady()) {
    debugLog('[getInvoiceById] Offline - invoice not found locally:', id)
    return null
  }

  // STEP 4: Try Firebase
  try {
    const docRef = doc(db!, COLLECTIONS.INVOICES, id)
    const docSnap = await getDoc(docRef)

    if (docSnap.exists()) {
      const invoice = docToInvoice(docSnap)
      if (filterByUserRole([invoice], userInfo).length === 0) {
        return null
      }
      // Cache in IndexedDB for future offline access
      saveToOffline(STORES.INVOICES, invoice).catch(() => {})
      debugLog('[getInvoiceById] Fetched from Firebase and cached:', id)
      return invoice
    }
    debugLog('[getInvoiceById] Not found in Firebase:', id)
    return null
  } catch (error) {
    console.error('[getInvoiceById] Firebase fetch failed:', error)
    return null
  }
}

/**
 * Create new invoice - OFFLINE FIRST
 * Always saves locally first, then syncs to server silently when online
 */
export async function createInvoice(invoiceData: Omit<Invoice, 'id' | 'createdAt' | 'updatedAt'>): Promise<Invoice | null> {
  const now = new Date().toISOString()
  const id = `invoice_${Date.now()}_${Math.random().toString(36).substr(2, 9)}`
  const invoiceCompanyId = String((invoiceData as any)?.companyId || '').trim()
  const companyId = invoiceCompanyId || getCurrentCompanyId()
  const userInfo = getCurrentUserInfo()
  const createdByUserName = userInfo?.displayName?.trim() || userInfo?.email?.trim()

  if (!companyId) {
    console.warn('[createInvoice] Missing companyId - cannot create invoice even for offline save')
    return null
  }

  const dedupKey = buildInvoiceCreateDedupKey(invoiceData as Partial<Invoice>, companyId)
  const existingRecentInvoice = findRecentExistingInvoiceByDedupKey(dedupKey, companyId)
  if (existingRecentInvoice) {
    console.warn('[createInvoice] Duplicate create prevented (recent match):', (invoiceData as any)?.invoiceNumber)
    return existingRecentInvoice
  }

  if (inFlightInvoiceCreateKeys.has(dedupKey)) {
    const pendingInvoice = await waitForRecentInvoiceByDedupKey(dedupKey, companyId)
    if (pendingInvoice) {
      console.warn('[createInvoice] Duplicate create prevented (in-flight match):', (invoiceData as any)?.invoiceNumber)
      return pendingInvoice
    }
    console.warn('[createInvoice] Duplicate create prevented while previous request is still in progress')
    return null
  }

  inFlightInvoiceCreateKeys.add(dedupKey)
  const invoiceTypeLabel =
    (invoiceData as any)?.type === 'purchase'
      ? 'purchase'
      : (invoiceData as any)?.type === 'quote'
        ? 'quotation'
        : 'invoice'
  const stopBlocking = startBlocking({
    title: `Saving ${invoiceTypeLabel}...`,
    description: 'Please wait. Do not close the app.'
  })

  try {

  // Remove undefined values - Firestore doesn't accept them
  const cleanData = Object.fromEntries(
    Object.entries(invoiceData).filter(([_, value]) => value !== undefined)
  )

  const normalizedInput = normalizeInvoicePaymentFields(cleanData as any) as Omit<Invoice, 'id' | 'createdAt' | 'updatedAt'>

  const newInvoice: Invoice = {
    ...normalizedInput,
    id,
    createdAt: now,
    updatedAt: now,
    ...(companyId ? { companyId } : {}),
    // Track who created this invoice (for role-based filtering)
    ...(userInfo?.uid ? { createdByUserId: userInfo.uid, createdByUserRole: userInfo.role } : {}),
    ...(createdByUserName ? { createdByUserName } : {}),
    // Offline-first metadata
    _pendingSync: !isDeviceOnline(),
    _savedAt: now,
    _syncedAt: null
  } as Invoice

  // STEP 1: Always save to local IndexedDB first (instant)
  try {
    await saveToOffline(STORES.INVOICES, newInvoice)
    // Also save to localStorage for backward compatibility
    saveInvoiceToLocalStorage(newInvoice)
  } catch (error) {
    console.error('Failed to save invoice locally:', error)
  }

  // Invalidate cache after creating
  invalidateCacheByPrefix('invoices')
  // Party outstanding balances are derived from invoices.
  invalidateCacheByPrefix('parties_outstanding_')
  emitDataEvent(DATA_EVENTS.INVOICES_CHANGED, { action: 'create' })
  emitDataEvent(DATA_EVENTS.PARTIES_CHANGED, { reason: 'invoice-change' })

  // STEP 2: If online, sync to Firestore silently
  if (isDeviceOnline() && isFirebaseReady()) {
    try {
      // Sanitize data to remove undefined values before sending to Firebase
      const dataToSync = sanitizeForFirebase({
        ...normalizedInput,
        createdAt: now,
        updatedAt: now,
        ...(companyId ? { companyId } : {}),
        // Track who created this invoice (for role-based filtering)
        ...(userInfo?.uid ? { createdByUserId: userInfo.uid, createdByUserRole: userInfo.role } : {}),
        ...(createdByUserName ? { createdByUserName } : {})
      })

      const docRef = await addDoc(collection(db!, COLLECTIONS.INVOICES), dataToSync)

      // Store original offline ID before updating
      const originalOfflineId = id

      // Update local invoice with server ID and mark as synced
      newInvoice.id = docRef.id
      newInvoice._pendingSync = false
      newInvoice._syncedAt = now

      // IMPORTANT: Delete the old offline ID record BEFORE saving the new Firebase ID record
      // This prevents duplicate entries in the list
      await deleteFromOffline(STORES.INVOICES, originalOfflineId)
      deleteInvoiceFromLocalStorage(originalOfflineId)

      // Now save with the new Firebase ID
      await saveToOffline(STORES.INVOICES, newInvoice)
      saveInvoiceToLocalStorage(newInvoice)

      // Re-emit after offline->server ID replacement so list screens reload with
      // the final canonical row and do not keep temporary duplicates.
      invalidateCacheByPrefix('invoices')
      invalidateCacheByPrefix('parties_outstanding_')
      emitDataEvent(DATA_EVENTS.INVOICES_CHANGED, {
        action: 'create-sync',
        id: docRef.id,
        replacedOfflineId: originalOfflineId
      })
      emitDataEvent(DATA_EVENTS.PARTIES_CHANGED, { reason: 'invoice-change' })

      debugLog('[createInvoice] ✅ Synced to Firebase, replaced offline ID:', originalOfflineId, '→', docRef.id)

    } catch (error) {
      // Silent fail - add to sync queue for later
      debugLog('Firestore save failed, queuing for sync:', id)
      await addToSyncQueue('create', STORES.INVOICES, newInvoice)
    }
  } else {
    // Offline - add to sync queue
    await addToSyncQueue('create', STORES.INVOICES, newInvoice)
  }

  // STEP 3: Update stock for each item in the invoice
  // SALE: Deduct stock, PURCHASE: Add stock
  try {
    await updateStockForInvoice(newInvoice)
  } catch (stockError) {
    console.error('Error updating stock for invoice:', stockError)
    // Don't throw - invoice is already created
  }

    recentCreatedInvoices.set(dedupKey, {
      invoice: newInvoice,
      timestamp: Date.now()
    })

    return newInvoice
  } finally {
    stopBlocking()
    inFlightInvoiceCreateKeys.delete(dedupKey)
  }
}

/**
 * Sync callback for offline invoices - called by offlineSyncService
 */
async function syncInvoiceToServer(syncItem: any): Promise<boolean> {
  if (syncItem.store !== STORES.INVOICES) return false

  const queuedInvoice = syncItem.data
  const invoice = queuedInvoice?.id
    ? (await getFromOffline<Invoice>(STORES.INVOICES, queuedInvoice.id)) || queuedInvoice
    : queuedInvoice
  if (!invoice || !isFirebaseReady()) return false

  try {
    if (syncItem.type === 'delete') {
      if (!invoice.id || isOfflineInvoiceId(invoice.id)) return true
      await deleteDoc(doc(db!, COLLECTIONS.INVOICES, invoice.id))
      invalidateCacheByPrefix('invoices')
      invalidateCacheByPrefix('parties_outstanding_')
      emitDataEvent(DATA_EVENTS.INVOICES_CHANGED, { action: 'sync-delete', id: invoice.id })
      emitDataEvent(DATA_EVENTS.PARTIES_CHANGED, { reason: 'invoice-change' })
      return true
    }

    // Remove offline metadata before sending to server
    const serverData = normalizeInvoicePaymentFields({ ...invoice } as any)
    delete serverData._pendingSync
    delete serverData._savedAt
    delete serverData._syncedAt
    delete serverData.id

    const companyId = getCurrentCompanyId()
    if (companyId) {
      serverData.companyId = companyId
    }

    // Sanitize data to remove undefined values (Firebase doesn't accept undefined)
    const now = new Date().toISOString()
    const sanitizedData = sanitizeForFirebase({
      ...serverData,
      updatedAt: now
    })

    if (syncItem.type === 'create' || isOfflineInvoiceId(invoice.id)) {
      const docRef = await addDoc(collection(db!, COLLECTIONS.INVOICES), sanitizedData)

      // Update local with server ID
      const updatedInvoice = {
        ...invoice,
        id: docRef.id,
        _pendingSync: false,
        _syncedAt: now
      }

      if (invoice.id && invoice.id !== docRef.id) {
        await deleteFromOffline(STORES.INVOICES, invoice.id)
        deleteInvoiceFromLocalStorage(invoice.id)
      }

      await saveToOffline(STORES.INVOICES, updatedInvoice)
      saveInvoiceToLocalStorage(updatedInvoice)
    } else {
      await updateDoc(doc(db!, COLLECTIONS.INVOICES, invoice.id), sanitizedData)

      const updatedInvoice = {
        ...invoice,
        _pendingSync: false,
        _syncedAt: now
      }

      await saveToOffline(STORES.INVOICES, updatedInvoice)
      updateInvoiceInLocalStorage(invoice.id, updatedInvoice)
    }

    // Invalidate cache
    invalidateCacheByPrefix('invoices')
    invalidateCacheByPrefix('parties_outstanding_')
    emitDataEvent(DATA_EVENTS.INVOICES_CHANGED, { action: 'sync' })
    emitDataEvent(DATA_EVENTS.PARTIES_CHANGED, { reason: 'invoice-change' })

    return true
  } catch (error) {
    console.error('Failed to sync invoice to server:', error)
    return false
  }
}

// Register sync callback
registerSyncCallback(STORES.INVOICES, syncInvoiceToServer)

/**
 * Update stock quantities based on invoice type
 * SALE: Deduct stock (subtract)
 * PURCHASE: Add stock (add)
 * Also creates ledger entry for the party
 */
async function updateStockForInvoice(invoice: Invoice): Promise<void> {
  debugLog('📦 updateStockForInvoice called:', {
    type: invoice.type,
    invoiceNumber: invoice.invoiceNumber,
    itemsCount: invoice.items?.length || 0
  })

  try {
    // Update stock for each item
    if (!invoice.items || invoice.items.length === 0) {
      debugLog('⚠️ No items in invoice to update stock')
      return
    }

    for (const item of invoice.items) {
      if (item.itemId) {
        // Treat all non-purchase invoices as stock-out (sale/quotation reduce stock)
        const operation = invoice.type === 'purchase' ? 'add' : 'subtract'
        const success = await updateItemStock(item.itemId, item.quantity || item.qty || 0, operation)
        debugLog(`✅ Stock update for ${item.description || item.name}: ${success ? 'SUCCESS' : 'FAILED'}`)
      }
    }

    // Create ledger entry for the party
    if (invoice.partyId && invoice.partyName) {
      await createInvoiceLedgerEntry(
        invoice.partyId,
        invoice.partyName,
        invoice.invoiceNumber,
        invoice.invoiceDate,
        invoice.grandTotal || invoice.total || 0,
        invoice.type === 'purchase' ? 'purchase' : 'sale'
      )
    }
  } catch (error) {
    console.error('Error updating stock/ledger for invoice:', error)
  }
}

/**
 * Update existing invoice - OFFLINE FIRST
 * Always saves locally first, then syncs to Firebase silently when online
 */
export async function updateInvoice(id: string, updates: Partial<Invoice>): Promise<boolean> {
  debugLog('[updateInvoice] Starting offline-first update for:', id)
  const now = new Date().toISOString()
  const stopBlocking = startBlocking({
    title: 'Saving changes...',
    description: 'Please wait. Do not close the app.'
  })

  try {

  // Check if ID is offline-generated
  const isOfflineId = (invoiceId: string) => invoiceId.startsWith('invoice_') || invoiceId.startsWith('offline_')

  // STEP 1: Get existing invoice from local
  let existingInvoice: Invoice | null = null
  try {
    existingInvoice = await getFromOffline<Invoice>(STORES.INVOICES, id)
  } catch (error) {
    const localInvoices = getInvoicesFromLocalStorage()
    existingInvoice = localInvoices.find(i => i.id === id) || null
  }

  if (!existingInvoice) {
    console.error('[updateInvoice] Invoice not found:', id)
    return false
  }

    const mergedInvoice = normalizeInvoicePaymentFields({
      ...existingInvoice,
      ...updates
    } as any) as Invoice

    const updatedInvoice: Invoice = {
    ...mergedInvoice,
    updatedAt: now,
    _pendingSync: !isDeviceOnline() || isOfflineId(id),
    _savedAt: now
  } as Invoice

  // STEP 2: Always save to IndexedDB first
  try {
    await saveToOffline(STORES.INVOICES, updatedInvoice)
    updateInvoiceInLocalStorage(id, updatedInvoice)
    debugLog('[updateInvoice] ✅ Updated locally:', id)
  } catch (error) {
    console.error('[updateInvoice] Local save failed:', error)
    updateInvoiceInLocalStorage(id, updatedInvoice)
  }

  // Invalidate cache after update
  invalidateCacheByPrefix('invoices')
  invalidateCacheByPrefix('parties_outstanding_')
  emitDataEvent(DATA_EVENTS.INVOICES_CHANGED, { action: 'update', id })
  emitDataEvent(DATA_EVENTS.PARTIES_CHANGED, { reason: 'invoice-change' })

  // STEP 3: If online and not an offline-only record, sync to Firebase
  if (isDeviceOnline() && isFirebaseReady() && !isOfflineId(id)) {
    try {
      const normalizedServerUpdates = normalizeInvoicePaymentFields({
        ...existingInvoice,
        ...updates
      } as any)
      const serverDataRaw: any = {
        ...updates,
        updatedAt: now
      }
      if ((updates as any).payment !== undefined) {
        serverDataRaw.payment = normalizedServerUpdates.payment
      }
      if ((updates as any).payment !== undefined || (updates as any).paymentStatus !== undefined) {
        serverDataRaw.paymentStatus = normalizedServerUpdates.paymentStatus
      }
      const serverData = sanitizeForFirebase(serverDataRaw)
      const docRef = doc(db!, COLLECTIONS.INVOICES, id)
      await updateDoc(docRef, serverData)

      // Mark as synced
      const syncedInvoice = {
        ...updatedInvoice,
        _pendingSync: false,
        _syncedAt: now
      }
      await saveToOffline(STORES.INVOICES, syncedInvoice)

      debugLog('[updateInvoice] ✅ Synced to Firebase:', id)
    } catch (error) {
      console.warn('[updateInvoice] Firebase sync failed, queuing:', error)
      await addToSyncQueue('update', STORES.INVOICES, updatedInvoice)
    }
  } else if (!isOfflineId(id)) {
    await addToSyncQueue('update', STORES.INVOICES, updatedInvoice)
  }

  return true
  } finally {
    stopBlocking()
  }
}

/**
 * Delete invoice - OFFLINE FIRST with FULL REVERSAL of all effects
 * Works for BOTH sales and purchase invoices
 */
export async function deleteInvoice(id: string, invoiceHint?: Partial<Invoice> | null): Promise<boolean> {
  debugLog('[deleteInvoice] Starting offline-first deletion with full reversal for:', id)

  // Check if ID is offline-generated (not yet synced to Firebase)
  const isOfflineId = id.startsWith('invoice_') || id.startsWith('offline_')
  
  // STEP 1: Get the full invoice data BEFORE deletion (to know what to reverse)
  let invoiceToDelete: Invoice | null = null
  try {
    invoiceToDelete = await getInvoiceById(id)
    debugLog('[deleteInvoice] Found invoice to delete:', {
      id: invoiceToDelete?.id,
      number: invoiceToDelete?.invoiceNumber,
      type: invoiceToDelete?.type,
      partyId: invoiceToDelete?.partyId,
      partyName: invoiceToDelete?.partyName,
      itemsCount: invoiceToDelete?.items?.length
    })
  } catch (error) {
    console.error('[deleteInvoice] Failed to fetch invoice before deletion:', error)
  }

  if (!invoiceToDelete && invoiceHint) {
    invoiceToDelete = invoiceHint as Invoice
    debugLog('[deleteInvoice] Using invoice hint for deletion fallback:', {
      id: invoiceToDelete?.id,
      number: invoiceToDelete?.invoiceNumber,
      type: invoiceToDelete?.type,
      partyName: invoiceToDelete?.partyName
    })
  }

  if (!invoiceToDelete) {
    console.warn('[deleteInvoice] Invoice not found, cannot reverse effects')
    // Still try to delete if it exists somewhere
  }

  // STEP 2: REVERSE STOCK EFFECTS (CRITICAL!)
  if (invoiceToDelete?.items && invoiceToDelete.items.length > 0) {
    debugLog('[deleteInvoice] Reversing stock for', invoiceToDelete.items.length, 'items')
    
    for (const item of invoiceToDelete.items) {
      if (item.itemId) {
        try {
          // Determine the REVERSE operation based on invoice type
          // For purchases: when deleting, we SUBTRACT the stock that was ADDED
          // For sales: when deleting, we ADD BACK the stock that was SOLD
          let operation: 'add' | 'subtract'
          
          if (invoiceToDelete.type === 'purchase') {
            // Purchase originally ADDED stock, so deleting should SUBTRACT
            operation = 'subtract'
          } else {
            // Sale originally SUBTRACTED stock, so deleting should ADD back
            operation = 'add'
          }
          
          const qty = item.quantity || item.qty || 0
          
          debugLog(`[deleteInvoice] Reversing stock for item ${item.itemId}:`, {
            originalType: invoiceToDelete.type,
            reverseOperation: operation,
            qty
          })
          
          // Use the existing updateItemStock function with REVERSE operation
          const { updateItemStock } = await import('./itemService')
          const success = await updateItemStock(item.itemId, qty, operation)
          
          if (success) {
            debugLog(`[deleteInvoice] Stock reversed successfully for item ${item.itemId}`)
          } else {
            console.warn(`[deleteInvoice] Stock reversal returned false for item ${item.itemId}`)
          }
        } catch (stockError) {
          console.error(`[deleteInvoice] Failed to reverse stock for item ${item.itemId}:`, stockError)
          // Continue with deletion even if stock reversal fails
        }
      } else {
        debugLog('[deleteInvoice] Item has no itemId, skipping stock reversal:', item)
      }
    }
  }

  // STEP 3: REVERSE LEDGER ENTRIES
  if (invoiceToDelete?.partyId && invoiceToDelete?.partyName) {
    try {
      debugLog('[deleteInvoice] Reversing ledger entries for party:', {
        partyId: invoiceToDelete.partyId,
        partyName: invoiceToDelete.partyName,
        invoiceNumber: invoiceToDelete.invoiceNumber,
        type: invoiceToDelete.type
      })
      
      // Import ledger service
      const { reverseLedgerEntry } = await import('./ledgerService')
      
      // Reverse the invoice ledger entry
      await reverseLedgerEntry(
        invoiceToDelete.partyId,
        invoiceToDelete.invoiceNumber,
        `${invoiceToDelete.type === 'purchase' ? 'Purchase' : 'Sales'} Invoice Deleted`
      )
      
      debugLog('[deleteInvoice] Ledger entry reversed successfully')
    } catch (ledgerError) {
      console.error('[deleteInvoice] Failed to reverse ledger entry:', ledgerError)
      // Continue with deletion even if ledger reversal fails
    }
  } else {
    debugLog('[deleteInvoice] Cannot reverse ledger - missing party info:', {
      partyId: invoiceToDelete?.partyId,
      partyName: invoiceToDelete?.partyName
    })
  }

  // STEP 4: REVERSE PAYMENTS (if any)
  if (invoiceToDelete?.id) {
    try {
      // Get all payments for this invoice
      const { getInvoicePayments, deletePayment } = await import('./paymentService')
      const payments = await getInvoicePayments(invoiceToDelete.id)
      
      if (payments && payments.length > 0) {
        debugLog('[deleteInvoice] Found', payments.length, 'payments to reverse')
        
        // Reverse each payment (delete payment records)
        for (const payment of payments) {
          try {
            await deletePayment(payment.id, invoiceToDelete.id)
            debugLog('[deleteInvoice] Reversed payment:', payment.id)
          } catch (paymentError) {
            console.error('[deleteInvoice] Failed to reverse payment:', payment.id, paymentError)
          }
        }
        
        // Also update banking/cash if needed (handled by deletePayment)
        debugLog('[deleteInvoice] All payments reversed')
      } else {
        debugLog('[deleteInvoice] No payments found to reverse')
      }
    } catch (paymentsError) {
      console.error('[deleteInvoice] Failed to fetch/reverse payments:', paymentsError)
      // Continue with deletion
    }
  }

  // STEP 5: NOW ACTUALLY DELETE THE INVOICE
  let deletionSuccess = false
  let localStorageDeleted = false
  let firebaseDeleted = false
  
  // Delete from IndexedDB first
  try {
    await deleteFromOffline(STORES.INVOICES, id)
    debugLog('[deleteInvoice] ✅ Deleted from IndexedDB:', id)
    deletionSuccess = true
  } catch (error) {
    console.warn('[deleteInvoice] IndexedDB delete failed:', error)
  }

  // Delete from localStorage
  localStorageDeleted = deleteInvoiceFromLocalStorage(id) || deleteInvoiceVariantsFromLocalStorage(id, invoiceToDelete)
  if (localStorageDeleted) {
    debugLog('[deleteInvoice] ✅ Deleted from localStorage:', id)
    deletionSuccess = true
  }
  
  // If we have a Firebase ID (not offline ID) and online, delete from Firebase
  if (!isOfflineId && isDeviceOnline() && isFirebaseReady()) {
    try {
      const docRef = doc(db!, COLLECTIONS.INVOICES, id)
      await deleteDoc(docRef)
      debugLog('[deleteInvoice] ✅ Deleted from Firebase:', id)

      // Legacy purchase documents may exist in a separate collection for older records.
      if ((invoiceToDelete?.type || '').toLowerCase() === 'purchase') {
        const legacyPurchaseRef = doc(db!, 'purchases', id)
        await deleteDoc(legacyPurchaseRef)
        debugLog('[deleteInvoice] ✅ Deleted from legacy purchases collection:', id)
      }

      firebaseDeleted = true
      deletionSuccess = true
    } catch (error) {
      console.warn('[deleteInvoice] Firebase delete failed, queuing:', error)
      // Queue for sync if online delete fails
      await addToSyncQueue('delete', STORES.INVOICES, { id })
      deletionSuccess = deletionSuccess || localStorageDeleted
    }
  } else if (!isOfflineId) {
    // Queue for sync if has Firebase ID but currently offline
    await addToSyncQueue('delete', STORES.INVOICES, { id })
    deletionSuccess = deletionSuccess || localStorageDeleted
  }

  // STEP 6: EMIT EVENTS to refresh UI
  if (deletionSuccess) {
    // Invalidate cache
    invalidateCacheByPrefix('invoices')
    invalidateCacheByPrefix('parties_outstanding_')
    
    // Emit events for UI refresh
    emitDataEvent(DATA_EVENTS.INVOICES_CHANGED, { 
      action: 'delete', 
      id,
      type: invoiceToDelete?.type,
      reversal: true
    })
    emitDataEvent(DATA_EVENTS.PARTIES_CHANGED, { 
      reason: 'invoice-deleted',
      partyId: invoiceToDelete?.partyId
    })
    emitDataEvent(DATA_EVENTS.ITEMS_CHANGED, { 
      reason: 'invoice-deleted',
      items: invoiceToDelete?.items?.map(i => i.itemId).filter(Boolean)
    })
    
    debugLog('[deleteInvoice] ✅ Emitted refresh events')
  }

  debugLog('[deleteInvoice] Final deletion result:', {
    id,
    deletionSuccess,
    localStorageDeleted,
    firebaseDeleted
  })

  return deletionSuccess
}

/**
 * Process scanned invoice data and create invoice with auto-created parties and items
 */
export async function processScannedInvoice(
  scannedData: ScannedInvoiceData,
  type: 'sale' | 'purchase',
  businessGSTIN: string = '33AAAAA0000A1Z5' // Replace with actual business GSTIN
): Promise<{ invoice: Invoice | null; party: any; items: any[] }> {
  try {
    const currentUser = getCurrentUserInfo()
    const billingStaffName = currentUser?.displayName?.trim() || currentUser?.email?.trim() || null

    // Determine party based on invoice type
    const partyData = type === 'purchase' ? scannedData.vendor : scannedData.buyer || scannedData.vendor
    const partyType = type === 'purchase' ? 'supplier' : 'customer'

    // Step 1: Find or create party
    const party = await findOrCreatePartyFromInvoice(
      partyData.name,
      partyData.gstin,
      partyData.phone,
      partyData.email,
      partyData.address,
      partyData.city,
      partyData.state,
      partyData.pinCode,
      partyType
    )

    if (!party) {
      throw new Error('Failed to create/find party')
    }

    // Step 2: Find or create items
    const processedItems = []
    const invoiceItems = []

    const scannedDiscountAmount = Number(scannedData.discountAmount || 0)
    const scannedDiscountPercent = Number(scannedData.discountPercent || 0)

    for (const scannedItem of scannedData.items) {
      const quantity = Math.max(1, round2(scannedItem.quantity || 1))
      const taxRate = round2(scannedItem.gstRate || scannedData.cgstRate + scannedData.sgstRate + scannedData.igstRate || 18)
      const lineDiscountAmount = round2(scannedItem.discountAmount || 0)
      const lineTaxableAmount = round2(
        scannedItem.taxableValue ??
        Math.max(0, (Number(scannedItem.amount || 0) - Number(scannedItem.gstAmount || 0)))
      )
      const baseLineAmount = round2(
        lineTaxableAmount > 0
          ? lineTaxableAmount + lineDiscountAmount
          : Number(scannedItem.rate || 0) * quantity
      )
      const unitBaseRate = round2(quantity > 0 ? (baseLineAmount / quantity) : Number(scannedItem.rate || 0))
      const lineDiscountPercent = round2(
        scannedItem.discountPercent ??
        (baseLineAmount > 0 ? (lineDiscountAmount / baseLineAmount) * 100 : 0)
      )
      const lineGstAmount = round2(
        scannedItem.gstAmount ??
        (lineTaxableAmount * taxRate / 100)
      )
      const lineTotalAmount = round2(
        scannedItem.amount ??
        (lineTaxableAmount + lineGstAmount)
      )

      const item = await findOrCreateItemFromInvoice(
        scannedItem.description,
        scannedItem.hsnCode,
        unitBaseRate,
        scannedItem.unit,
        taxRate,
        type,
        {
          manufacturer: scannedItem.manufacturer,
          batchNo: scannedItem.batchNo,
          expiryDate: scannedItem.expiryDate,
          packageType: scannedItem.packageType,
          mrp: scannedItem.mrp,
          discountPercent: lineDiscountPercent,
          discountAmount: lineDiscountAmount
        }
      )

      if (item) {
        processedItems.push(item)
        const partyStateCode = party.gstDetails?.stateCode || '33'
        const businessStateCode = businessGSTIN.substring(0, 2)
        const isIntraState = (type === 'purchase' ? businessStateCode : partyStateCode) === (type === 'purchase' ? partyStateCode : businessStateCode)
        const cgstPercent = isIntraState ? round2(taxRate / 2) : 0
        const sgstPercent = isIntraState ? round2(taxRate / 2) : 0
        const igstPercent = isIntraState ? 0 : taxRate
        const cgstAmount = isIntraState ? round2(lineGstAmount / 2) : 0
        const sgstAmount = isIntraState ? round2(lineGstAmount / 2) : 0
        const igstAmount = isIntraState ? 0 : lineGstAmount

        invoiceItems.push({
          id: `item_${Date.now()}_${Math.random().toString(36).substr(2, 9)}`,
          itemId: item.id,
          itemName: item.name,
          description: scannedItem.description,
          hsnCode: scannedItem.hsnCode,
          quantity,
          unit: scannedItem.unit,
          rate: unitBaseRate,
          discountPercent: lineDiscountPercent,
          discountAmount: lineDiscountAmount,
          taxableAmount: lineTaxableAmount,
          taxRate,
          cgstPercent,
          cgstAmount,
          sgstPercent,
          sgstAmount,
          igstPercent,
          igstAmount,
          taxAmount: lineGstAmount,
          amount: lineTaxableAmount,
          totalAmount: lineTotalAmount
        })
      }
    }

    // Step 3: Calculate invoice totals
    const totals = calculateInvoiceTotals({
      items: invoiceItems.map(i => ({
        amount: i.taxableAmount,
        cgstAmount: i.cgstAmount,
        sgstAmount: i.sgstAmount,
        igstAmount: i.igstAmount
      }))
    })

    // Step 4: Create invoice
    const invoiceData: Omit<Invoice, 'id' | 'createdAt' | 'updatedAt'> = {
      type,
      invoiceNumber: scannedData.invoiceNumber,
      invoiceDate: scannedData.invoiceDate,
      partyId: party.id,
      partyName: party.companyName,
      partyGSTIN: party.gstDetails?.gstin,
      partyAddress: party.billingAddress,
      partyPhone: party.phone,
      partyEmail: party.email,
      businessName: 'Sandra ERP',
      businessGSTIN,
      businessAddress: {
        street: '',
        city: '',
        state: '',
        pinCode: '',
        country: 'India'
      },
      businessPhone: '',
      businessEmail: '',
      businessStateCode: businessGSTIN.substring(0, 2),
      referenceNumber: scannedData.referenceNumber,
      buyerOrderNumber: scannedData.buyerOrderNumber,
      deliveryNoteNumber: scannedData.deliveryNoteNumber,
      items: invoiceItems,
      subtotal: totals.subtotal,
      discountPercent: scannedDiscountPercent,
      discountAmount: scannedDiscountAmount,
      taxableAmount: totals.taxableAmount,
      cgstAmount: totals.cgstTotal,
      sgstAmount: totals.sgstTotal,
      igstAmount: totals.igstTotal,
      cessAmount: 0,
      totalTaxAmount: totals.totalTax,
      shippingCharges: 0,
      otherCharges: 0,
      roundOff: scannedData.roundOff,
      grandTotal: scannedData.grandTotal,
      payment: {
        mode: scannedData.paymentMode === 'Mode/Terms of Payment' ? 'cash' : 'cash',
        status: 'unpaid',
        paidAmount: 0,
        dueAmount: scannedData.grandTotal
      },
      transport: scannedData.vehicleNumber ? {
        vehicleNumber: scannedData.vehicleNumber,
        destination: scannedData.destination
      } : undefined,
      termsOfDelivery: scannedData.termsOfPayment,
      status: 'approved',
      createdBy: billingStaffName || 'AI Scanner',

      // Billing Staff (Accountant) metadata from login
      billingStaffId: currentUser?.uid || null,
      billingStaffName,
      billingStaffRole: currentUser?.role || null,
      billingStaffEmail: currentUser?.email?.trim() || null
    }

    const invoice = await createInvoice(invoiceData)

    return {
      invoice,
      party,
      items: processedItems
    }
  } catch (error) {
    console.error('Error processing scanned invoice:', error)
    return {
      invoice: null,
      party: null,
      items: []
    }
  }
}

// Helper function to convert Firestore document to Invoice
function docToInvoice(doc: QueryDocumentSnapshot<DocumentData>): Invoice {
  const data = normalizeInvoicePaymentFields(doc.data() as any)
  return {
    ...data,
    id: doc.id
  } as Invoice
}

// ============================================
// LOCAL STORAGE FALLBACK FUNCTIONS
// ============================================

function getInvoicesFromLocalStorage(type?: 'sale' | 'purchase' | 'quote', limitCount?: number): Invoice[] {
  try {
    const companyId = getCurrentCompanyId()
    if (!companyId) return []

    const stored = getLocalJSON<Invoice[]>(getLocalStorageKey(), [])
    let invoices: Invoice[] = Array.isArray(stored)
      ? stored.map(inv => normalizeInvoicePaymentFields(inv as any) as Invoice)
      : []

    invoices = invoices.filter(i => (i as any).companyId === companyId)

    if (type) {
      invoices = invoices.filter(i => i.type === type)
    }

    // Sort by date descending
    invoices.sort((a, b) => new Date(b.invoiceDate).getTime() - new Date(a.invoiceDate).getTime())
    invoices = dedupeInvoicesByIdentity(invoices, companyId)

    if (limitCount) {
      invoices = invoices.slice(0, limitCount)
    }

    return invoices
  } catch (error) {
    console.error('Error reading invoices from local storage:', error)
    return []
  }
}

function saveInvoiceToLocalStorage(invoice: Invoice): void {
  try {
    const storageKey = getLocalStorageKey()
    const invoices = getMutableLocalJSON<Invoice[]>(storageKey, [])
    if (!Array.isArray(invoices)) return
    invoices.push(normalizeInvoicePaymentFields(invoice as any) as Invoice)
    markLocalJSONDirty(storageKey)
  } catch (error) {
    console.error('Error saving invoice to local storage:', error)
  }
}

function updateInvoiceInLocalStorage(id: string, updates: Partial<Invoice>): boolean {
  try {
    const storageKey = getLocalStorageKey()
    const invoices = getMutableLocalJSON<Invoice[]>(storageKey, [])
    if (!Array.isArray(invoices)) return false
    const index = invoices.findIndex(i => i.id === id)

    if (index === -1) return false

    invoices[index] = normalizeInvoicePaymentFields({ ...invoices[index], ...updates } as any) as Invoice
    markLocalJSONDirty(storageKey)
    return true
  } catch (error) {
    console.error('Error updating invoice in local storage:', error)
    return false
  }
}

function deleteInvoiceFromLocalStorage(id: string): boolean {
  try {
    const storageKey = getLocalStorageKey()
    const invoices = getMutableLocalJSON<Invoice[]>(storageKey, [])
    if (!Array.isArray(invoices)) return false
    const idx = invoices.findIndex(i => i.id === id)
    if (idx === -1) return false
    invoices.splice(idx, 1)
    markLocalJSONDirty(storageKey)
    return true
  } catch (error) {
    console.error('Error deleting invoice from local storage:', error)
    return false
  }
}

function deleteInvoiceVariantsFromLocalStorage(id: string, invoiceToDelete?: Invoice | null): boolean {
  try {
    const storageKey = getLocalStorageKey()
    const invoices = getMutableLocalJSON<Invoice[]>(storageKey, [])
    if (!Array.isArray(invoices)) return false

    const targetInvoiceNumber = String(invoiceToDelete?.invoiceNumber || '').trim().toLowerCase()
    const targetType = String(invoiceToDelete?.type || '').trim().toLowerCase()
    const targetParty = String(invoiceToDelete?.partyName || '').trim().toLowerCase()
    const targetDate = String(invoiceToDelete?.invoiceDate || '').trim()

    const originalLength = invoices.length
    const filtered = invoices.filter(inv => {
      if (inv.id === id) return false

      if (!targetInvoiceNumber) return true

      const sameIdentity =
        String(inv.invoiceNumber || '').trim().toLowerCase() === targetInvoiceNumber &&
        String(inv.type || '').trim().toLowerCase() === targetType &&
        String(inv.partyName || '').trim().toLowerCase() === targetParty &&
        String(inv.invoiceDate || '').trim() === targetDate

      return !sameIdentity
    })

    if (filtered.length === originalLength) return false

    invoices.splice(0, invoices.length, ...filtered)
    markLocalJSONDirty(storageKey)
    return true
  } catch (error) {
    console.error('Error deleting invoice variants from local storage:', error)
    return false
  }
}
