// Ledger Service
// Manages party ledger entries - tracks all financial transactions with customers/suppliers

import {
  collection,
  doc,
  addDoc,
  getDocs,
  query,
  where,
  orderBy,
  Timestamp
} from 'firebase/firestore'
import { db, COLLECTIONS, isFirebaseReady } from './firebase'
import { getPartySettings } from './settingsService'
import { getCurrentCompanyId, getScopedStorageKey } from '../utils/authUtils'

const LOCAL_STORAGE_KEY = 'thisai_crm_ledger_entries'
const getLocalStorageKey = () => getScopedStorageKey(LOCAL_STORAGE_KEY, 'company')

export interface LedgerEntry {
  id: string
  partyId: string
  partyName: string
  date: string
  companyId?: string
  type: 'invoice' | 'payment' | 'opening_balance' | 'adjustment'
  referenceType: 'sale' | 'purchase' | 'payment' | 'opening' | 'adjustment'
  referenceNumber: string
  description: string
  debit: number  // Money customer owes us (sales) or we pay supplier
  credit: number // Money we receive from customer or owe supplier (purchases)
  balance: number // Running balance
  createdAt: string
}

export interface LedgerEntryInput {
  partyId: string
  partyName: string
  date: string
  type: 'invoice' | 'payment' | 'opening_balance' | 'adjustment'
  referenceType: 'sale' | 'purchase' | 'payment' | 'opening' | 'adjustment'
  referenceNumber: string
  description: string
  debit: number
  credit: number
}

// Helper to get the correct collection name
const getLedgerCollectionName = () => {
  // Make sure this matches your Firebase collection name exactly
  return 'party_ledger' // or 'parties_ledger' or whatever your actual collection is named
}

const canReachCloud = (): boolean => navigator.onLine && isFirebaseReady()

/**
 * Create ledger entry for invoice
 * Only creates entry if trackLedgerAutomatically is enabled in Party Settings
 */
export async function createInvoiceLedgerEntry(
  partyId: string,
  partyName: string,
  invoiceNumber: string,
  invoiceDate: string,
  amount: number,
  type: 'sale' | 'purchase'
): Promise<void> {
  // Check if automatic ledger tracking is enabled
  const partySettings = getPartySettings()
  console.log('🎯 createInvoiceLedgerEntry called:', { 
    partyId, 
    partyName, 
    invoiceNumber, 
    amount, 
    type, 
    trackEnabled: partySettings.trackLedgerAutomatically 
  })
  
  if (!partySettings.trackLedgerAutomatically) {
    console.log(`Ledger tracking disabled - skipping entry for invoice ${invoiceNumber}`)
    return
  }

  try {
    const entry: LedgerEntryInput = {
      partyId,
      partyName,
      date: invoiceDate,
      type: 'invoice',
      referenceType: type,
      referenceNumber: invoiceNumber,
      description: type === 'sale'
        ? `Sales Invoice ${invoiceNumber}`
        : `Purchase Invoice ${invoiceNumber}`,
      debit: type === 'sale' ? amount : 0,  // Customer owes us (for sales)
      credit: type === 'purchase' ? amount : 0  // We owe supplier (for purchases)
    }

    console.log('📝 About to create ledger entry:', entry)
    await createLedgerEntry(entry)
    console.log(`✅ Ledger entry created: ${type} invoice ${invoiceNumber} for ${partyName}`)
  } catch (error) {
    console.error('❌ Error creating invoice ledger entry:', error)
  }
}

/**
 * Create ledger entry for payment
 * Only creates entry if trackLedgerAutomatically is enabled in Party Settings
 */
export async function createPaymentLedgerEntry(
  partyId: string,
  partyName: string,
  paymentDate: string,
  amount: number,
  paymentReference: string,
  type: 'sale' | 'purchase'
): Promise<void> {
  // Check if automatic ledger tracking is enabled
  const partySettings = getPartySettings()
  console.log('🎯 createPaymentLedgerEntry called:', { 
    partyId, 
    partyName, 
    paymentReference, 
    amount, 
    type, 
    trackEnabled: partySettings.trackLedgerAutomatically 
  })
  
  if (!partySettings.trackLedgerAutomatically) {
    console.log(`Ledger tracking disabled - skipping entry for payment ${paymentReference}`)
    return
  }

  try {
    const entry: LedgerEntryInput = {
      partyId,
      partyName,
      date: paymentDate,
      type: 'payment',
      referenceType: 'payment',
      referenceNumber: paymentReference,
      description: type === 'sale'
        ? `Payment Received - ${paymentReference}`
        : `Payment Made - ${paymentReference}`,
      debit: type === 'purchase' ? amount : 0,  // We pay supplier (reduces liability)
      credit: type === 'sale' ? amount : 0  // We receive from customer (reduces receivable)
    }

    console.log('📝 About to create payment ledger entry:', entry)
    await createLedgerEntry(entry)
    console.log(`✅ Ledger entry created: Payment ${paymentReference} for ${partyName}`)
  } catch (error) {
    console.error('Error creating payment ledger entry:', error)
  }
}

/**
 * Create a ledger entry and calculate running balance
 */
async function createLedgerEntry(entryInput: LedgerEntryInput): Promise<void> {
  const companyId = getCurrentCompanyId()
  if (!companyId) {
    console.warn('[createLedgerEntry] Missing companyId - skipping ledger entry')
    return
  }
  
  console.log('💾 createLedgerEntry started:', { entryInput, companyId })
  
  // Get current balance for this party
  const existingEntries = await getPartyLedger(entryInput.partyId)
  console.log('📊 Existing entries count:', existingEntries.length)
  
  const lastBalance = existingEntries.length > 0
    ? existingEntries[existingEntries.length - 1].balance
    : 0

  console.log('💰 Last balance:', lastBalance)

  // Calculate new balance
  // Debit increases balance (customer owes more or we pay supplier)
  // Credit decreases balance (we receive payment or purchase from supplier)
  const newBalance = lastBalance + entryInput.debit - entryInput.credit
  console.log('🧮 New balance calculation:', { 
    lastBalance, 
    debit: entryInput.debit, 
    credit: entryInput.credit, 
    newBalance 
  })

  const entry: Omit<LedgerEntry, 'id'> = {
    ...entryInput,
    companyId,
    balance: newBalance,
    createdAt: new Date().toISOString()
  }

  // ALWAYS save to localStorage first (as backup)
  console.log('📱 Saving to localStorage as backup...')
  const localId = saveLedgerEntryToLocalStorage(entry)
  console.log('📱 Saved to localStorage with ID:', localId)

  // Then try Firebase if available
  if (canReachCloud()) {
    try {
      console.log('☁️ Attempting to save to Firebase...')
      const collectionName = getLedgerCollectionName()
      console.log('📁 Using collection:', collectionName)
      
      const docRef = await addDoc(collection(db!, collectionName), entry)
      console.log('✅ Saved to Firebase with ID:', docRef.id)
    } catch (error) {
      console.error('❌ Error creating ledger entry in Firebase:', error)
      console.log('📱 Already saved to localStorage as fallback')
      // Don't throw - we already saved to localStorage
    }
  } else {
    console.log('📱 Offline or Firebase not ready, saved only to localStorage')
  }
}

/**
 * Reverse a ledger entry (for invoice deletions)
 * Creates a reversing entry that nullifies the original transaction
 */
export async function reverseLedgerEntry(
  partyId: string,
  referenceNumber: string,
  reversalReason: string = 'Invoice Deleted'
): Promise<void> {
  console.log('🔄 reverseLedgerEntry called:', { partyId, referenceNumber, reversalReason })
  
  const companyId = getCurrentCompanyId()
  if (!companyId) {
    console.warn('[reverseLedgerEntry] Missing companyId - skipping reversal')
    return
  }

  try {
    // Get the original entry to reverse
    const entries = await getPartyLedger(partyId)
    const originalEntry = entries.find(e => e.referenceNumber === referenceNumber)
    
    if (!originalEntry) {
      console.warn('[reverseLedgerEntry] Original entry not found for:', referenceNumber)
      return
    }

    console.log('[reverseLedgerEntry] Found original entry:', originalEntry)

    // Create a reversing entry
    // For reversal: debit becomes credit, credit becomes debit
    const reversalEntry: LedgerEntryInput = {
      partyId,
      partyName: originalEntry.partyName,
      date: new Date().toISOString().split('T')[0],
      type: 'adjustment',
      referenceType: 'adjustment',
      referenceNumber: `REV-${referenceNumber}`,
      description: `Reversal of ${originalEntry.type} ${referenceNumber} - ${reversalReason}`,
      debit: originalEntry.credit,  // Reverse: credit becomes debit
      credit: originalEntry.debit    // Reverse: debit becomes credit
    }

    console.log('[reverseLedgerEntry] Creating reversal entry:', reversalEntry)
    await createLedgerEntry(reversalEntry)
    console.log('[reverseLedgerEntry] Reversal entry created successfully')
  } catch (error) {
    console.error('[reverseLedgerEntry] Error creating reversal:', error)
    throw error
  }
}

/**
 * Get all ledger entries for a party
 */
export async function getPartyLedger(partyId: string): Promise<LedgerEntry[]> {
  console.log('🔍 getPartyLedger called for party:', partyId)
  
  const companyId = getCurrentCompanyId()
  if (!companyId) {
    console.warn('❌ No companyId found')
    return []
  }
  
  console.log('🏢 Company ID:', companyId)
  
  let firebaseEntries: LedgerEntry[] = []
  let localEntries: LedgerEntry[] = []
  
  // Try to get from Firebase
  if (canReachCloud()) {
    try {
      console.log('☁️ Querying Firebase...')
      const collectionName = getLedgerCollectionName()
      console.log('📁 Using collection:', collectionName)
      
      const q = query(
        collection(db!, collectionName),
        where('companyId', '==', companyId),
        where('partyId', '==', partyId),
        orderBy('date', 'asc'),
        orderBy('createdAt', 'asc')
      )

      const snapshot = await getDocs(q)
      console.log('☁️ Firebase snapshot size:', snapshot.size)
      
      firebaseEntries = snapshot.docs.map(doc => {
        const data = doc.data()
        return {
          id: doc.id,
          ...data
        } as LedgerEntry
      })
      
      console.log('✅ Firebase entries found:', firebaseEntries.length)
      if (firebaseEntries.length > 0) {
        console.log('📋 First Firebase entry:', firebaseEntries[0])
        console.log('📋 Last Firebase entry:', firebaseEntries[firebaseEntries.length - 1])
      }
    } catch (error) {
      console.error('❌ Error fetching party ledger from Firebase:', error)
    }
  } else {
    console.log('📱 Skipping Firebase ledger fetch because browser is offline')
  }
  
  // Always get from localStorage too
  console.log('📱 Getting from localStorage...')
  localEntries = getPartyLedgerFromLocalStorage(partyId)
  console.log('📱 localStorage entries found:', localEntries.length)
  if (localEntries.length > 0) {
    console.log('📋 First localStorage entry:', localEntries[0])
    console.log('📋 Last localStorage entry:', localEntries[localEntries.length - 1])
  }
  
  // Combine and deduplicate entries
  const allEntries = [...firebaseEntries, ...localEntries]
  console.log('📊 Total entries before dedup:', allEntries.length)
  
  // Remove duplicates by creating a Map with unique key
  const uniqueEntries = new Map<string, LedgerEntry>()
  allEntries.forEach(entry => {
    // Create a unique key based on date, referenceNumber, type, and amount
    const key = `${entry.date}_${entry.referenceNumber}_${entry.type}_${entry.debit}_${entry.credit}`
    if (!uniqueEntries.has(key)) {
      uniqueEntries.set(key, entry)
    } else {
      console.log('⚠️ Duplicate entry found and skipped:', key)
    }
  })
  
  const combinedEntries = Array.from(uniqueEntries.values())
  
  // Sort by date and createdAt
  combinedEntries.sort((a, b) => {
    const dateCompare = new Date(a.date).getTime() - new Date(b.date).getTime()
    if (dateCompare !== 0) return dateCompare
    return new Date(a.createdAt).getTime() - new Date(b.createdAt).getTime()
  })
  
  console.log('📊 Total unique entries after combining:', combinedEntries.length)
  
  return combinedEntries
}

/**
 * Get current balance for a party
 */
export async function getPartyBalance(partyId: string): Promise<number> {
  const ledger = await getPartyLedger(partyId)
  if (ledger.length === 0) return 0

  return ledger[ledger.length - 1].balance
}

/**
 * Get ledger summary for all parties
 */
export async function getLedgerSummary(): Promise<{
  totalReceivables: number  // Customers owe us
  totalPayables: number     // We owe suppliers
  netBalance: number
}> {
  const companyId = getCurrentCompanyId()
  if (!companyId) {
    return { totalReceivables: 0, totalPayables: 0, netBalance: 0 }
  }
  
  let firebaseEntries: LedgerEntry[] = []
  let localEntries: LedgerEntry[] = []
  
  // Try Firebase first
  if (isFirebaseReady()) {
    try {
      const collectionName = getLedgerCollectionName()
      const q = query(
        collection(db!, collectionName),
        where('companyId', '==', companyId)
      )
      const snapshot = await getDocs(q)
      firebaseEntries = snapshot.docs.map(doc => doc.data() as LedgerEntry)
      console.log('☁️ Firebase summary entries:', firebaseEntries.length)
    } catch (error) {
      console.error('Error getting ledger summary from Firebase:', error)
    }
  }
  
  // Get from localStorage
  localEntries = getLedgerEntriesFromLocalStorage()
  console.log('📱 localStorage summary entries:', localEntries.length)
  
  // Combine all entries
  const allEntries = [...firebaseEntries, ...localEntries]
  
  // Sort entries to get the latest balance for each party
  const sortedEntries = allEntries.sort((a, b) => {
    const dateCompare = new Date(a.date).getTime() - new Date(b.date).getTime()
    if (dateCompare !== 0) return dateCompare
    return new Date(a.createdAt).getTime() - new Date(b.createdAt).getTime()
  })

  const partyBalances = new Map<string, number>()
  sortedEntries.forEach(entry => {
    partyBalances.set(entry.partyId, entry.balance)
  })

  let totalReceivables = 0
  let totalPayables = 0

  partyBalances.forEach(balance => {
    if (balance > 0) {
      totalReceivables += balance  // Customers owe us
    } else if (balance < 0) {
      totalPayables += Math.abs(balance)  // We owe suppliers
    }
  })

  return {
    totalReceivables,
    totalPayables,
    netBalance: totalReceivables - totalPayables
  }
}

// ============================================
// LOCAL STORAGE FALLBACK
// ============================================

function saveLedgerEntryToLocalStorage(entry: Omit<LedgerEntry, 'id'>): string {
  try {
    const entries = getLedgerEntriesFromLocalStorage()
    const newEntry: LedgerEntry = {
      ...entry,
      id: `ledger_${Date.now()}_${Math.random().toString(36).substr(2, 9)}`
    }
    entries.push(newEntry)
    localStorage.setItem(getLocalStorageKey(), JSON.stringify(entries))
    console.log('📱 Saved to localStorage, total entries:', entries.length)
    return newEntry.id
  } catch (error) {
    console.error('Error saving ledger entry to local storage:', error)
    return ''
  }
}

function getLedgerEntriesFromLocalStorage(): LedgerEntry[] {
  try {
    const companyId = getCurrentCompanyId()
    if (!companyId) return []

    const stored = localStorage.getItem(getLocalStorageKey())
    const entries: LedgerEntry[] = stored ? JSON.parse(stored) : []
    const filtered = entries.filter(entry => entry.companyId === companyId)
    console.log('📱 Read from localStorage, entries:', filtered.length)
    return filtered
  } catch (error) {
    console.error('Error reading ledger entries from local storage:', error)
    return []
  }
}

function getPartyLedgerFromLocalStorage(partyId: string): LedgerEntry[] {
  const allEntries = getLedgerEntriesFromLocalStorage()
  const filtered = allEntries
    .filter(entry => entry.partyId === partyId)
    .sort((a, b) => {
      const dateCompare = new Date(a.date).getTime() - new Date(b.date).getTime()
      if (dateCompare !== 0) return dateCompare
      return new Date(a.createdAt).getTime() - new Date(b.createdAt).getTime()
    })
  console.log('📱 Party ledger from localStorage:', { partyId, entriesFound: filtered.length })
  return filtered
}

